public sealed class PaymentStatementEntity:PostgreSqlEntity { public string StatementNumber {get;set;}=string.Empty; public string SupplierRut {get;set;}=string.Empty; public decimal Amount {get;set;} public string Currency {get;set;}="CLP"; public string Status {get;set;}="Pendiente"; public string? ContractCode {get;set;} public Guid? FaenaId {get;set;} public FaenaEntity? Faena {get;set;} public string? DocumentUrl {get;set;} public string CreatedByUserId {get;set;}=string.Empty; public string? UpdatedByUserId {get;set;} public DateTimeOffset? StatusChangedAtUtc {get;set;} public string? RejectReason {get;set;} }
